(333,	'_elementor_notifications_data',	'a:2:{s:7:\"timeout\";i:1778072289;s:5:\"value\";s:8561:\"[{\"id\":\"4.0-default\",\"title\":\"The new default\",\"description\":\"New sites now start with version 4.0 and atomic features enabled by default. Existing sites can choose to manually activate. Nothing happens to your existing layouts and sites.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-default.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"4.0-atomic-forms\",\"title\":\"Atomic Forms\",\"description\":\"Build forms as part of your layout, not separate widgets. Create flexible, multi-column designs, nest elements freely, and maintain full control with the same atomic system and styling logic.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-atomic-form.png\",\"chipPlan\":\"Pro\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"elementor-pro\\/elementor-pro.php\"}]]},{\"id\":\"4.0-atomic-forms\",\"title\":\"Atomic Forms\",\"description\":\"Build forms as part of your layout, not separate widgets. Create flexible, multi-column designs, nest elements freely, and maintain full control with the same atomic system and styling logic.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/3.33-custom-css.png\",\"chipTags\":[\"Atomic Editor\"],\"cta\":\"Upgrade\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-atomic-forms\\/\"},{\"id\":\"4.0-interactions\",\"title\":\"Pro Interactions\",\"description\":\"Create advanced, lightweight motion inside the Editor. Define behavior visually, keep everything system-based, and deliver engaging experiences without bloated scripts or external tools.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-interactions.png\",\"chipPlan\":\"Pro\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\",\"conditions\":[[{\"type\":\"plugin\",\"plugin\":\"elementor-pro\\/elementor-pro.php\"}]]},{\"id\":\"4.0-interactions\",\"title\":\"Pro Interactions\",\"description\":\"Create advanced, lightweight motion inside the Editor. Define behavior visually, keep everything system-based, and deliver engaging experiences without bloated scripts or external tools.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-interactions.png\",\"chipTags\":[\"Atomic Editor\"],\"cta\":\"Upgrade\",\"ctaLink\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-interactions\\/\"},{\"id\":\"4.0-sync-design-system\",\"title\":\"Sync and share design systems\",\"description\":\"Export and import Variables and Classes between sites, and sync them with v3 Global Styles. Maintain a consistent design system across projects and across versions.\",\"topic\":\"Version 4.0\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/4.0-sync-design-system.png\",\"chipTags\":[\"Atomic Editor\"],\"link\":\"https:\\/\\/go.elementor.com\\/go-pro-notification-4.0-blog\\/\",\"readMoreText\":\"Learn More\"},{\"id\":\"angie-launch\",\"title\":\"Introducing Angie Code.\",\"description\":\"Create custom Elementor widgets, and snippets for custom site functionality from a simple description. Built natively for WordPress, and Elementor. Preview safely, refine through conversation, and publish when ready.\",\"topic\":\"Angie Code\",\"imageSrc\":\"https:\\/\\/assets.elementor.com\\/notifications\\/v1\\/images\\/angie-launch.png\",\"chipTags\":[\"New launch\"],\"link\":\"https:\